.segment	"CODE"

.proc	_bank_pop: near

.segment	"CODE"

;
; if (bankLevel != 0) {
;
	lda     _bankLevel
	beq     L0011
;
; --bankLevel;
;
	dec     _bankLevel
;
; set_prg_bank(bankBuffer[bankLevel]);
;
	ldy     _bankLevel
	lda     _bankBuffer,y
	jmp     _set_prg_bank
;
; }
;
L0011:	rts

.endproc

